// ═══════════════════════════════════════════════
// SILVER MARKET INTELLIGENCE — PROMPT BUILDER
// ═══════════════════════════════════════════════

// --- Helper: Parse RSS XML text ---
function parseRSSXml(xmlText) {
  if (!xmlText || typeof xmlText !== 'string') return [];
  const items = [];
  const itemBlocks = xmlText.match(/<item[\s\S]*?<\/item>/gi) || [];
  for (const block of itemBlocks.slice(0, 7)) {
    // Title — handles both CDATA and plain text
    const titleMatch =
      block.match(/<title><!\[CDATA\[([\s\S]*?)\]\]><\/title>/i) ||
      block.match(/<title>([\s\S]*?)<\/title>/i);
    // Description / summary
    const descMatch =
      block.match(/<description><!\[CDATA\[([\s\S]*?)\]\]><\/description>/i) ||
      block.match(/<description>([\s\S]*?)<\/description>/i) ||
      block.match(/<summary>([\s\S]*?)<\/summary>/i);
    // Date
    const dateMatch =
      block.match(/<pubDate>([\s\S]*?)<\/pubDate>/i) ||
      block.match(/<published>([\s\S]*?)<\/published>/i);

    const title = (titleMatch?.[1] || '').replace(/<[^>]+>/g, '').trim();
    const desc  = (descMatch?.[1]  || '').replace(/<[^>]+>/g, '').substring(0, 300).trim();
    const date  = (dateMatch?.[1]  || '').trim();

    if (title) items.push({ title, description: desc, pubDate: date });
  }
  return items;
}

// --- 1. Silver Spot Price (Yahoo Finance) ---
let currentPrice = 'N/A', prevClose = 'N/A', high52w = 'N/A', low52w = 'N/A';
let priceChangePct = 0;
try {
  const silverRaw = $('Get Silver Price1').first().json;
  const meta = silverRaw?.chart?.result?.[0]?.meta || {};
  currentPrice   = (meta.regularMarketPrice   || 0).toFixed(2);
  prevClose      = (meta.chartPreviousClose   || 0).toFixed(2);
  high52w        = (meta.fiftyTwoWeekHigh     || 0).toFixed(2);
  low52w         = (meta.fiftyTwoWeekLow      || 0).toFixed(2);
  priceChangePct = prevClose > 0
    ? parseFloat((((currentPrice - prevClose) / prevClose) * 100).toFixed(2))
    : 0;
} catch(e) { currentPrice = 'Unavailable'; }

// --- 2. Parse Yahoo Finance Silver RSS ---
let yahooSection = 'No Yahoo Finance silver news retrieved.';
try {
  const rawXml = $('Yahoo Finance Silver RSS').first().json.data || '';
  const items  = parseRSSXml(rawXml);
  if (items.length > 0) {
    yahooSection = items.map(i =>
      `• ${i.title}\n  🕐 ${i.pubDate}\n  ${i.description}`
    ).join('\n\n');
  }
} catch(e) { yahooSection = 'Yahoo Finance RSS error: ' + e.message; }

// --- 3. Parse Investing.com Commodities RSS ---
let investingSection = 'No Investing.com commodities news retrieved.';
try {
  const rawXml = $('Investing.com Commodities RSS').first().json.data || '';
  const items  = parseRSSXml(rawXml);
  if (items.length > 0) {
    investingSection = items.map(i =>
      `• ${i.title}\n  🕐 ${i.pubDate}\n  ${i.description}`
    ).join('\n\n');
  }
} catch(e) { investingSection = 'Investing.com RSS error: ' + e.message; }

// --- 4. Date string (Amman timezone) ---
const today = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
  timeZone: 'Asia/Amman'
});

const changeArrow = priceChangePct > 0 ? '▲' : priceChangePct < 0 ? '▼' : '—';
const changeSign  = priceChangePct > 0 ? '+' : '';

// --- 5. Assemble the full prompt ---
const userMessage = `
SILVER MARKET INTELLIGENCE BRIEF
Date: ${today}
${'═'.repeat(50)}

📊 SILVER FUTURES PRICE DATA (SI=F — Yahoo Finance)
${'─'.repeat(50)}
Current Spot Price : $${currentPrice} / oz
Previous Close     : $${prevClose} / oz
Day Change         : ${changeArrow} ${changeSign}${priceChangePct}%
52-Week High       : $${high52w} / oz
52-Week Low        : $${low52w} / oz

${'═'.repeat(50)}
📰 YAHOO FINANCE — Silver News
${'─'.repeat(50)}
${yahooSection}

${'═'.repeat(50)}
📰 INVESTING.COM — Commodities News
${'─'.repeat(50)}
${investingSection}

${'═'.repeat(50)}

Please analyze everything above and provide your full structured silver market assessment following your system instructions exactly.
`.trim();

return [{
  json: {
    userMessage,
    currentPrice:   parseFloat(currentPrice) || 0,
    prevClose:      parseFloat(prevClose) || 0,
    priceChangePct,
    high52w:        parseFloat(high52w) || 0,
    low52w:         parseFloat(low52w) || 0,
    today
  }
}];

